// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





function getConditionMeta(condition: string) {
  const normalized = condition.toLowerCase();
  if (normalized.includes('rain') || normalized.includes('drizzle') || normalized.includes('shower')) {
    return { emoji: '🌧️', label: 'Rainy' };
  }
  if (normalized.includes('snow') || normalized.includes('sleet') || normalized.includes('blizzard')) {
    return { emoji: '❄️', label: 'Snowy' };
  }
  if (normalized.includes('thunder') || normalized.includes('storm')) {
    return { emoji: '⛈️', label: 'Stormy' };
  }
  if (normalized.includes('cloud') || normalized.includes('overcast') || normalized.includes('fog') || normalized.includes('mist')) {
    return { emoji: '☁️', label: 'Cloudy' };
  }
  if (normalized.includes('wind')) {
    return { emoji: '💨', label: 'Windy' };
  }
  return { emoji: '☀️', label: 'Sunny' };
}

function formatTemp(value: number, unit: string) {
  return `${Math.round(value)}°${unit || 'C'}`;
}

function formatWindSpeed(value: number) {
  return `${Math.round(value)} mph`;
}

function getDayLabel(day?: string, index?: number) {
  if (day && day.trim()) return day;
  if (typeof index === 'number') {
    const date = new Date();
    date.setDate(date.getDate() + index + 1);
    return date.toLocaleDateString(undefined, { weekday: 'short' });
  }
  return '—';
}

function getForecastMeta(icon?: string, day?: string) {
  const source = `${icon ?? ''} ${day ?? ''}`.toLowerCase();
  if (source.includes('rain')) return { emoji: '🌧️', label: 'Rain' };
  if (source.includes('snow')) return { emoji: '❄️', label: 'Snow' };
  if (source.includes('storm') || source.includes('thunder')) return { emoji: '⛈️', label: 'Storm' };
  if (source.includes('cloud')) return { emoji: '☁️', label: 'Cloud' };
  if (source.includes('wind')) return { emoji: '💨', label: 'Wind' };
  if (source.includes('fog') || source.includes('mist')) return { emoji: '🌫️', label: 'Fog' };
  return { emoji: '☀️', label: 'Sunny' };
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const conditionMeta = useMemo(() => getConditionMeta(props.condition), [props.condition]);
  const forecastItems = useMemo(() => (Array.isArray(props.forecast) ? props.forecast.slice(0, 5) : []), [props.forecast]);
  const hasForecast = forecastItems.length > 0;
  const summary = useMemo(() => `${formatTemp(props.temperature, props.unit)} • ${conditionMeta.label}`, [props.temperature, props.unit, conditionMeta.label]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <MotionKeyframes />
      <Card
        shadow="lg"
        radius="xl"
        padding="var(--ggui-spacing-6)"
      >
        <Stack gap="var(--ggui-spacing-6)">
          <Box
            padding="var(--ggui-spacing-6)"
            background="var(--ggui-color-container)"
            borderRadius="var(--ggui-shape-radius-lg)"
          >
            <Stack gap="var(--ggui-spacing-4)">
              <Row align="center">
                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="overline" color="var(--ggui-color-onContainer)">Current weather</Text>
                  <Heading level={2} color="var(--ggui-color-onContainer)">{props.city}</Heading>
                </Stack>
                <Spacer size="flex" />
                <Badge variant="primary" size="lg">{conditionMeta.label}</Badge>
              </Row>

              <Row align="center" gap="var(--ggui-spacing-4)" wrap>
                <Text as="span" size="4xl" weight="bold" color="var(--ggui-color-onContainer)">
                  {formatTemp(props.temperature, props.unit)}
                </Text>
                <Text variant="bodyLarge" color="var(--ggui-color-onContainer)">
                  {conditionMeta.emoji} {props.condition}
                </Text>
              </Row>

              <Text variant="bodySmall" color="var(--ggui-color-onContainer)">
                {summary}
              </Text>
            </Stack>
          </Box>

          <Card padding="var(--ggui-spacing-5)" shadow="sm" radius="lg">
            <Stack gap="var(--ggui-spacing-4)">
              <Row gap="var(--ggui-spacing-4)" wrap>
                <Box
                  padding="var(--ggui-spacing-4)"
                  background="var(--ggui-color-surfaceVariant)"
                  borderRadius="var(--ggui-shape-radius-md)"
                >
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                    <Heading level={4}>{Math.round(props.humidity)}%</Heading>
                  </Stack>
                </Box>
                <Box
                  padding="var(--ggui-spacing-4)"
                  background="var(--ggui-color-surfaceVariant)"
                  borderRadius="var(--ggui-shape-radius-md)"
                >
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Wind speed</Text>
                    <Heading level={4}>{formatWindSpeed(props.windSpeed)}</Heading>
                  </Stack>
                </Box>
                <Box
                  padding="var(--ggui-spacing-4)"
                  background="var(--ggui-color-surfaceVariant)"
                  borderRadius="var(--ggui-shape-radius-md)"
                >
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Temperature unit</Text>
                    <Heading level={4}>{props.unit}</Heading>
                  </Stack>
                </Box>
              </Row>
            </Stack>
          </Card>

          <Stack gap="var(--ggui-spacing-3)">
            <Row align="center">
              <Heading level={4}>5-day forecast</Heading>
              <Spacer size="flex" />
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                {hasForecast ? 'Updated forecast outlook' : 'No forecast available'}
              </Text>
            </Row>
            <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="lg">
              {hasForecast ? (
                <Row gap="var(--ggui-spacing-3)" wrap>
                  {forecastItems.map((item, index) => {
                    const meta = getForecastMeta(item.icon, item.day);
                    return (
                      <Box
                        key={`${getDayLabel(item.day, index)}-${index}`}
                        padding="var(--ggui-spacing-3)"
                        background="var(--ggui-color-surfaceVariant)"
                        borderRadius="var(--ggui-shape-radius-md)"
                      >
                        <Stack gap="var(--ggui-spacing-2)" align="center">
                          <Text variant="label" align="center">{getDayLabel(item.day, index)}</Text>
                          <Text size="2xl" aria-hidden="true">{meta.emoji}</Text>
                          <Text variant="bodySmall" align="center">{meta.label}</Text>
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" align="center">
                            H {typeof item.high === 'number' ? formatTemp(item.high, props.unit) : '—'}
                          </Text>
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" align="center">
                            L {typeof item.low === 'number' ? formatTemp(item.low, props.unit) : '—'}
                          </Text>
                        </Stack>
                      </Box>
                    );
                  })}
                </Row>
              ) : (
                <Alert variant="info" title="Forecast unavailable">
                  Provide forecast data to display the 5-day outlook.
                </Alert>
              )}
            </Card>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

