// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





function isValidEmail(value: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value.trim());
}

function clampComments(value: string): string {
  return value.length > 500 ? value.slice(0, 500) : value;
}

function asDisplayList(value: string[]): string {
  return value.length ? value.join(', ') : 'None selected';
}

function stepToProgress(step: number): number {
  return Math.max(0, Math.min(100, ((step - 1) / 3) * 100));
}

function ratingOptionsFromProps(labels: string[]): { value: string; label: string }[] {
  return Array.from({ length: 5 }, (_, index) => ({
    value: String(index + 1),
    label: labels[index] ?? `Rating ${index + 1}`,
  }));
}

function getStepTitle(step: number): string {
  switch (step) {
    case 1:
      return 'Your details';
    case 2:
      return 'Satisfaction';
    case 3:
      return 'Feature interests';
    case 4:
      return 'Comments & review';
    default:
      return 'Survey';
  }
}

export default function Component(props: Props) {
  const submit = useAction<ActionSubmitPayload>('submit');
  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [touched, setTouched] = useState({ name: false, email: false });
  const [submitted, setSubmitted] = useState(false);
  const [reviewing, setReviewing] = useState(false);

  const featureOptions = useMemo(() => props.featureOptions ?? [], [props.featureOptions]);
  const ratingOptions = useMemo(() => ratingOptionsFromProps(props.satisfactionLabels ?? []), [props.satisfactionLabels]);
  const nameError = touched.name && !name.trim() ? 'Name is required.' : '';
  const emailError = touched.email && !email.trim() ? 'Email is required.' : touched.email && !isValidEmail(email) ? 'Please enter a valid email address.' : '';
  const currentComments = clampComments(comments);
  const commentsCount = currentComments.length;
  const satisfactionNumber = Number(satisfaction || 0);
  const step1Valid = Boolean(name.trim()) && Boolean(email.trim()) && isValidEmail(email);
  const step2Valid = Boolean(satisfaction);
  const step3Valid = true;
  const canGoNext = step === 1 ? step1Valid : step === 2 ? step2Valid : step === 3 ? step3Valid : true;
  const progressValue = stepToProgress(step);

  useEffect(() => {
    if (comments !== currentComments) {
      setComments(currentComments);
    }
  }, [comments, currentComments]);

  const toggleFeature = useCallback((feature: string) => {
    setFeatures((current) =>
      current.includes(feature) ? current.filter((item) => item !== feature) : [...current, feature]
    );
  }, []);

  const goNext = useCallback(() => {
    if (step === 1) {
      setTouched({ name: true, email: true });
      if (!step1Valid) return;
    }
    if (step === 2 && !step2Valid) return;
    setStep((current) => Math.min(4, current + 1));
  }, [step, step1Valid, step2Valid]);

  const goBack = useCallback(() => {
    setStep((current) => Math.max(1, current - 1));
  }, []);

  const handleSubmit = useCallback(() => {
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction: satisfactionNumber || 1,
      features,
      comments: currentComments,
    });
    setSubmitted(true);
  }, [submit, name, email, satisfactionNumber, features, currentComments]);

  const reviewRows = useMemo(() => ([
    { label: 'Name', value: name.trim() || '—' },
    { label: 'Email', value: email.trim() || '—' },
    { label: 'Satisfaction', value: ratingOptions.find((option) => option.value === satisfaction)?.label ?? '—' },
    { label: 'Feature interests', value: asDisplayList(features) },
    { label: 'Comments', value: currentComments || 'No comments provided.' },
  ]), [name, email, ratingOptions, satisfaction, features, currentComments]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">

      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            <Row align="center" justify="between">
              <Stack gap="var(--ggui-spacing-1)">
                <Heading level={2}>Multi-step survey</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  Step {step} of 4 • {getStepTitle(step)}
                </Text>
              </Stack>
              <Badge variant={submitted ? 'success' : 'primary'}>{submitted ? 'Submitted' : 'In progress'}</Badge>
            </Row>
            <Progress value={progressValue} max={100} showLabel />
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg">
          <Stack gap="var(--ggui-spacing-6)">
            {submitted ? (
              <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg">
                <Stack gap="var(--ggui-spacing-4)">
                  <Badge variant="success">Submitted</Badge>
                  <Heading level={3}>Thanks for completing the survey.</Heading>
                  <Text color="var(--ggui-color-onSurfaceVariant)">
                    Your responses have been recorded successfully.
                  </Text>
                  <Divider />
                  <Stack gap="var(--ggui-spacing-3)">
                    <Heading level={4}>Final review</Heading>
                    {reviewRows.map((row) => (
                      <Box key={row.label} padding="var(--ggui-spacing-3)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                        <Stack gap="var(--ggui-spacing-1)">
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{row.label}</Text>
                          <Text>{row.value}</Text>
                        </Stack>
                      </Box>
                    ))}
                  </Stack>
                  <Button variant="outline" onClick={() => { setSubmitted(false); setStep(1); }}>
                    Submit another response
                  </Button>
                </Stack>
              </Card>
            ) : (
              <>
                {step === 1 && (
                  <Stack gap="var(--ggui-spacing-4)">
                    <Stack gap="var(--ggui-spacing-2)">
                      <Heading level={3}>Tell us about yourself</Heading>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                        We&apos;ll use this to personalize your survey response.
                      </Text>
                    </Stack>
                    <Input label="Name" value={name} onChange={(value) => setName(value)} required error={nameError} placeholder="Your full name" />
                    <Input label="Email" type="email" value={email} onChange={(value) => setEmail(value)} required error={emailError} placeholder="you@example.com" />
                  </Stack>
                )}

                {step === 2 && (
                  <Stack gap="var(--ggui-spacing-4)">
                    <Heading level={3}>How satisfied are you?</Heading>
                    <RadioGroup
                      label="Satisfaction rating"
                      value={satisfaction}
                      onChange={setSatisfaction}
                      options={ratingOptions}
                      direction="vertical"
                    />
                  </Stack>
                )}

                {step === 3 && (
                  <Stack gap="var(--ggui-spacing-4)">
                    <Heading level={3}>Which features interest you?</Heading>
                    <Stack gap="var(--ggui-spacing-2)">
                      {featureOptions.length ? featureOptions.map((feature) => (
                        <Checkbox
                          key={feature}
                          label={feature}
                          checked={features.includes(feature)}
                          onChange={() => toggleFeature(feature)}
                        />
                      )) : (
                        <Text color="var(--ggui-color-onSurfaceVariant)">No feature options provided.</Text>
                      )}
                    </Stack>
                  </Stack>
                )}

                {step === 4 && (
                  <Stack gap="var(--ggui-spacing-4)">
                    <Stack gap="var(--ggui-spacing-2)">
                      <Heading level={3}>Comments and review</Heading>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                        Add any final thoughts, then confirm your responses below.
                      </Text>
                    </Stack>
                    <TextArea
                      label="Comments"
                      value={comments}
                      onChange={(value) => setComments(clampComments(value))}
                      placeholder="Share anything else we should know..."
                      rows={6}
                      maxLength={500}
                      showCount
                    />
                <Row align="center" justify="between">
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                    {commentsCount}/500 characters
                  </Text>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                    You can add up to 500 characters.
                  </Text>
                </Row>
                <Divider />
                <Stack gap="var(--ggui-spacing-3)">
                  <Heading level={4}>Final review</Heading>
                  {reviewRows.map((row) => (
                    <Box key={row.label} padding="var(--ggui-spacing-3)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                      <Stack gap="var(--ggui-spacing-1)">
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{row.label}</Text>
                        <Text>{row.value}</Text>
                      </Stack>
                    </Box>
                  ))}
                </Stack>
              </Stack>
            )}

            <Divider />

            <Row align="center" justify="between" wrap>
              <Button variant="outline" onClick={goBack} disabled={step === 1}>Back</Button>
              <Spacer size="flex" />
              {step < 4 ? (
                <Button variant="primary" onClick={goNext} disabled={!canGoNext}>Next</Button>
              ) : (
                <Button variant="primary" onClick={handleSubmit}>Submit survey</Button>
              )}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Card>
  );
}
}

