function normalizeSpecifications(specifications: unknown[] | undefined): Array<{ key: string; value: string }> {
  if (!Array.isArray(specifications)) return [];
  return specifications
    .map((item, index) => {
      if (Array.isArray(item) && item.length >= 2) {
        return { key: String(item[0]), value: String(item[1]) };
      }
      if (item && typeof item === 'object') {
        const maybeObj = item as Record<string, unknown>;
        const key = maybeObj.key ?? maybeObj.name ?? maybeObj.label ?? maybeObj.title ?? `Spec ${index + 1}`;
        const value = maybeObj.value ?? maybeObj.description ?? maybeObj.detail ?? maybeObj.content ?? '';
        return { key: String(key), value: String(value) };
      }
      return { key: `Spec ${index + 1}`, value: String(item) };
    })
    .filter((item) => item.key.trim().length > 0);
}

function normalizeReviews(reviews: unknown[] | undefined): Array<{ author: string; rating: number; text: string; date: string }> {
  if (!Array.isArray(reviews)) return [];
  return reviews.map((item, index) => {
    if (item && typeof item === 'object') {
      const record = item as Record<string, unknown>;
      const author = String(record.author ?? record.name ?? record.user ?? `Reviewer ${index + 1}`);
      const ratingValue = typeof record.rating === 'number' && Number.isFinite(record.rating) ? record.rating : 0;
      const text = String(record.text ?? record.review ?? record.content ?? record.comment ?? '');
      const dateValue = record.date ?? record.createdAt ?? record.timestamp ?? '';
      const date = dateValue instanceof Date ? dateValue.toLocaleDateString() : String(dateValue);
      return { author, rating: Math.max(0, Math.min(5, Math.round(ratingValue))), text, date };
    }
