            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Change</Text>
            <Row align="center" gap="var(--ggui-spacing-2)">
              <Icon name={isPositive ? 'triangle-up' : 'triangle-down'} size={14} color={changeColor} />
              <Text weight="semibold" color={changeColor}>
                {stock.change >= 0 ? '+' : ''}{stock.change.toFixed(2)}
              </Text>
              <Text weight="semibold" color={changeColor}>
                ({isPositive ? '+' : ''}{stock.changePercent.toFixed(2)}%)
              </Text>
            </Row>
          </Stack>
        </Row>
      </Stack>
    </Card>
  );
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  const [lastUpdated, setLastUpdated] = React.useState<Date>(new Date());
  const [stocks, setStocks] = React.useState<StockRow[]>(() => (Array.isArray(props.stocks) ? props.stocks.map(normalizeStock).filter(Boolean) as StockRow[] : []));
  const [flashMap, setFlashMap] = React.useState<Record<string, number>>({});

  useEffect(() => {
    setStocks(Array.isArray(props.stocks) ? props.stocks.map(normalizeStock).filter(Boolean) as StockRow[] : []);
  }, [props.stocks]);

  useEffect(() => {
    const timer = setInterval(() => setLastUpdated(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    if (!marketStatus.latest?.timestamp) return;
    const parsed = new Date(marketStatus.latest.timestamp);
    if (!Number.isNaN(parsed.getTime())) {
      setLastUpdated(parsed);
    }
  }, [marketStatus.latest?.timestamp]);

  useEffect(() => {
    if (!priceUpdate.latest) return;
    setStocks((current) => mergeStockUpdates(current, Array.isArray(priceUpdate.latest) ? priceUpdate.latest : [priceUpdate.latest]));
    const latestUpdates = Array.isArray(priceUpdate.latest) ? priceUpdate.latest : [priceUpdate.latest];
    const now = Date.now();
    setFlashMap((current) => {
      const next = { ...current };
      latestUpdates.forEach((update) => {
        if (update.symbol) next[update.symbol] = now;
      });
      return next;
    });
  }, [priceUpdate.latest]);

  const marketStatusLabel = marketStatus.latest?.status ? marketStatus.latest.status.replace('-', ' ') : 'open';
  const connectedStocks = useMemo(() => stocks, [stocks]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      {/* live updates */}
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-5)" shadow="sm" radius="lg">
          <Row align="center" gap="var(--ggui-spacing-3)">
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={2}>Market Watch</Heading>
              <Text color="var(--ggui-color-onSurfaceVariant)">Live stock ticker dashboard</Text>
            </Stack>
            <Spacer size="flex" />
            <Stack gap="var(--ggui-spacing-1)" align="end">
              <Badge variant={marketStatus.latest?.status === 'closed' ? 'warning' : 'success'} size="sm">
                {marketStatusLabel}
              </Badge>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                Last Updated: {marketStatus.latest?.timestamp ? formatTimestamp(new Date(marketStatus.latest.timestamp)) : formatTimestamp(lastUpdated)}
              </Text>
            </Stack>
          </Row>
        </Card>
        {connectedStocks.length === 0 ? (
          <Alert variant="info" title="No stocks available">
            Waiting for stock data from props.
          </Alert>
        ) : (
          <Box
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))',
              gap: 'var(--ggui-spacing-4)',
            }}
          >
            {connectedStocks.map((stock) => (
              <Box key={stock.symbol}>
                <StockCard stock={stock} motionKey={flashMap[stock.symbol] ?? stock.updatedAt} />
              </Box>
            ))}
          </Box>
        )}
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





function getInitialStep(initialProfile: Props['initialProfile'] | undefined) {
  const profile = initialProfile || {};
  const hasName = Boolean(profile.name && profile.name.trim());
  const hasEmail = Boolean(profile.email && profile.email.trim());
  const hasAvatar = Boolean(profile.avatar && profile.avatar.trim());
  const hasRole = Boolean(profile.role && profile.role.trim());
  if (!hasName || !hasEmail || !hasAvatar) return 0;
  if (!hasRole) return 1;
  return 2;
}

function isValidEmail(email: string) {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim());
}

function themeLabel(theme: string) {
  return theme === 'dark' ? 'Dark' : 'Light';
}

function roleLabel(role: string) {
  if (!role) return 'Not selected';
  return role;
}

function avatarLabel(avatar: string) {
  return avatar || 'Not selected';
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  const avatarChoices = props.avatarOptions && props.avatarOptions.length > 0 ? props.avatarOptions : ['😀', '🎉', '✨', '🚀'];
  const roleChoices = props.roleOptions && props.roleOptions.length > 0 ? props.roleOptions : ['Developer', 'Designer', 'Manager', 'Other'];
  const initialProfile = props.initialProfile || {};
  const [step, setStep] = useState<number>(getInitialStep(initialProfile as Props['initialProfile']));
  const [name, setName] = useState<string>(initialProfile.name ?? '');
  const [email, setEmail] = useState<string>(initialProfile.email ?? '');
  const [avatar, setAvatar] = useState<string>(initialProfile.avatar ?? avatarChoices[0]);
  const [role, setRole] = useState<string>(initialProfile.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState<string>(initialProfile.theme ?? 'light');
  const [submitted, setSubmitted] = useState<boolean>(false);

  useEffect(() => {
    const nextInitialProfile = props.initialProfile || {};
    setName(nextInitialProfile.name ?? '');
    setEmail(nextInitialProfile.email ?? '');
    setAvatar(nextInitialProfile.avatar ?? avatarChoices[0]);
    setRole(nextInitialProfile.role ?? '');
    setEmailNotifications(nextInitialProfile.emailNotifications ?? true);
    setTheme(nextInitialProfile.theme ?? 'light');
    setStep(getInitialStep(nextInitialProfile as Props['initialProfile']));
    setSubmitted(false);
  }, [props.initialProfile, avatarChoices]);

  const nameError = submitted && !name.trim() ? 'Name is required.' : '';
  const emailError = submitted && !email.trim() ? 'Email is required.' : submitted && email.trim() && !isValidEmail(email) ? 'Enter a valid email address.' : '';
  const canContinueStep1 = Boolean(name.trim()) && Boolean(email.trim()) && isValidEmail(email) && Boolean(avatar.trim());
  const canContinueStep2 = Boolean(role.trim());
  const progressValue = ((step + 1) / 3) * 100;

  const goNext = useCallback(() => {
    if (step === 0 && !canContinueStep1) return;
    if (step === 1 && !canContinueStep2) return;
    setStep((current) => Math.min(2, current + 1));
  }, [step, canContinueStep1, canContinueStep2]);

  const goBack = useCallback(() => {
    setStep((current) => Math.max(0, current - 1));
  }, []);

  const handleComplete = useCallback(() => {
    setSubmitted(true);
    if (!canContinueStep1 || !canContinueStep2) {
      if (!canContinueStep1) {
        setStep(0);
      } else if (!canContinueStep2) {
        setStep(1);
      }
      return;
    }
    const payload: ActionCompletePayload = {
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    };
    complete(payload);
  }, [avatar, canContinueStep1, canContinueStep2, complete, email, emailNotifications, name, role, theme]);

  const summaryItems = useMemo(() => ([
    { label: 'Name', value: name.trim() || 'Not provided' },
    { label: 'Email', value: email.trim() || 'Not provided' },
    { label: 'Avatar', value: avatarLabel(avatar) },
    { label: 'Role', value: roleLabel(role) },
    { label: 'Notifications', value: emailNotifications ? 'On' : 'Off' },
    { label: 'Theme', value: themeLabel(theme) },
  ]), [avatar, email, emailNotifications, name, role, theme]);

  const stepTitles = ['Profile Setup', 'Preferences', 'Review & Confirm'];

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="md">
          <Stack gap="var(--ggui-spacing-4)">
            <Row align="center" justify="between">
              <Stack gap="var(--ggui-spacing-1)">
                <Badge variant="primary" size="sm">Step {step + 1} of 3</Badge>
                <Heading level={2}>Onboarding Wizard</Heading>
                <Text color="var(--ggui-color-onSurfaceVariant)">Complete your profile in three simple steps.</Text>
              </Stack>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{stepTitles[step]}</Text>
            </Row>
            <Progress value={progressValue} max={100} showLabel />
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="md">
          <Stack gap="var(--ggui-spacing-6)">
            <Box
              key={step}
              style={{ animation: 'ggui-fadeIn 200ms ease-out' }}
            >
              {step === 0 && (
                <Stack gap="var(--ggui-spacing-5)">
                  <Stack gap="var(--ggui-spacing-3)">
                    <Heading level={3}>Profile Setup</Heading>
                    <Text color="var(--ggui-color-onSurfaceVariant)">Tell us who you are and choose an avatar.</Text>
                  </Stack>
                  <Input
                    label="Name"
                    value={name}
                    onChange={setName}
                    placeholder="Your full name"
                    required
                    error={nameError}
                  />
                  <Input
                    label="Email"
                    type="email"
                    value={email}
                    onChange={setEmail}
                    placeholder="you@example.com"
                    required
                    error={emailError}
                    helperText="We will use this to keep your profile up to date."
                  />
                  <Stack gap="var(--ggui-spacing-3)">
                    <Text is="label" variant="label">Choose an avatar</Text>
                    <Row gap="var(--ggui-spacing-3)" wrap>
                      {avatarChoices.map((option) => (
                        <Card
                          key={option}
                          as={Clickable}
                          onClick={() => setAvatar(option)}
                          padding="var(--ggui-spacing-3)"
                          shadow={avatar === option ? 'md' : 'sm'}
                          border
                          radius="md"
                          style={{
                            borderColor: avatar === option ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outlineVariant)',
                            background: avatar === option ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                            transition: 'transform 200ms ease, border-color 200ms ease, background-color 200ms ease',
                          }}
                        >
                          <Stack gap="var(--ggui-spacing-2)" align="center">
                            <Avatar name={option} size="lg" shape="circle" />
                            <Text variant="bodyLarge">{option}</Text>
                          </Stack>
                        </Card>
                      ))}
                    </Row>
                  </Stack>
                </Stack>
              )}

              {step === 1 && (
                <Stack gap="var(--ggui-spacing-5)">
                  <Stack gap="var(--ggui-spacing-3)">
                    <Heading level={3}>Preferences</Heading>
                    <Text color="var(--ggui-color-onSurfaceVariant)">Customize your role, notifications, and appearance.</Text>
                  </Stack>
                  <Select
                    label="Role"
                    value={role}
                    onChange={setRole}
                    options={roleChoices.map((option) => ({ value: option, label: option }))}
                    placeholder="Select your role"
                    required
                    helperText="This helps tailor the experience to your workflow."
                  />
                  <Checkbox
                    label="Email notifications"
                    checked={emailNotifications}
                    onChange={setEmailNotifications}
                    description="Receive onboarding updates and important account messages by email."
                  />
                  <Toggle
                    label={`Theme preference: ${themeLabel(theme)}`}
                    checked={theme === 'dark'}
                    onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                    size="md"
                  />
                </Stack>
              )}

              {step === 2 && (
                <Stack gap="var(--ggui-spacing-5)">
                  <Stack gap="var(--ggui-spacing-3)">
                    <Heading level={3}>Review & Confirm</Heading>
                    <Text color="var(--ggui-color-onSurfaceVariant)">Review your selections before completing setup.</Text>
                  </Stack>
                  <Card padding="var(--ggui-spacing-4)" shadow="sm" border radius="md">
                    <Stack gap="var(--ggui-spacing-3)">
                      {summaryItems.map((item) => (
                        <Row key={item.label} justify="between" gap="var(--ggui-spacing-4)">
                          <Text color="var(--ggui-color-onSurfaceVariant)">{item.label}</Text>
                          <Text weight="medium" align="right">{item.value}</Text>
                        </Row>
                      ))}
                    </Stack>
                  </Card>
                  <Alert variant="info" title="Ready to finish?">
                    You can go back to edit any field before completing setup.
                  </Alert>
                </Stack>
              )}
            </Box>

            <Divider />

            <Row justify="between" align="center" gap="var(--ggui-spacing-3)">
              <Button
                variant="ghost"
                onClick={goBack}
                disabled={step === 0}
              >
                Go Back
              </Button>
              <Spacer size="flex" />
              {step < 2 ? (
                <Button
                  variant="primary"
                  onClick={goNext}
                  disabled={step === 0 ? !canContinueStep1 : !canContinueStep2}
                >
                  Next
                </Button>
              ) : (
                <Button variant="primary" onClick={handleComplete} disabled={!canContinueStep1 || !canContinueStep2}>
                  Complete Setup
                </Button>
              )}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}
